from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a comics character (or related entity)
    into a single fluent, complex sentence.
    """
    if not triples:
        return ""

    # Find the main subject (typically the comics character)
    main_subject = triples[0].subject

    # Group triples by predicate for better sentence construction
    predicate_data = {}
    for triple in triples:
        if triple.predicate not in predicate_data:
            predicate_data[triple.predicate] = []
        predicate_data[triple.predicate].append(triple.object)

    # Build sentence parts
    parts = []
    has_verb = False

    # Start with character name and optional full name
    if "fullName" in predicate_data:
        parts.append(f"{main_subject}, whose full name is {predicate_data['fullName'][0]}")
    else:
        parts.append(f"{main_subject}")

    # Add creator information
    if "creator" in predicate_data:
        parts.append(f" was created by {predicate_data['creator'][0]}")
        has_verb = True

    # Add alternative name
    if "alternativeName" in predicate_data:
        alt_name = predicate_data['alternativeName'][0].strip('"')
        if has_verb:
            parts.append(f", and is also known as {alt_name}")
        else:
            parts.append(f" is also known as {alt_name}")
            has_verb = True

    # Add birth place and nationality
    birth_info = []
    if "birthPlace" in predicate_data:
        birth_info.append(f"born in {predicate_data['birthPlace'][0]}")
    if "nationality" in predicate_data:
        nationality = predicate_data['nationality'][0]
        # Handle nationality more naturally (e.g., "French" instead of "French people")
        if nationality.endswith(" people"):
            nationality = nationality.replace(" people", "")
        birth_info.append(f"a {nationality}")

    if birth_info:
        birth_text = ", ".join(birth_info)
        if has_verb:
            parts.append(f", {birth_text}")
        else:
            parts.append(f" is {birth_text}")
            has_verb = True

    # Add voice actor
    if "voice" in predicate_data:
        if has_verb:
            parts.append(f", with voice provided by {predicate_data['voice'][0]}")
        else:
            parts.append(f" has voice provided by {predicate_data['voice'][0]}")
            has_verb = True

    # Add first appearance in film
    if "firstAppearanceInFilm" in predicate_data:
        if has_verb:
            parts.append(f" and first appeared in the film {predicate_data['firstAppearanceInFilm'][0]}")
        else:
            parts.append(f" first appeared in the film {predicate_data['firstAppearanceInFilm'][0]}")
            has_verb = True

    # Add series information
    if "series" in predicate_data:
        if has_verb:
            parts.append(f", as part of the {predicate_data['series'][0]} series")
        else:
            parts.append(f" as part of the {predicate_data['series'][0]} series")
            has_verb = True

    # Add starring information
    if "starring" in predicate_data:
        if has_verb:
            parts.append(f", starring {predicate_data['starring'][0]}")
        else:
            parts.append(f" starring {predicate_data['starring'][0]}")
            has_verb = True

    # Add awards
    if "award" in predicate_data:
        if has_verb:
            parts.append(f" and has received the {predicate_data['award'][0]}")
        else:
            parts.append(f" has received the {predicate_data['award'][0]}")
            has_verb = True

    # Add distributor
    if "distributor" in predicate_data:
        if has_verb:
            parts.append(f", distributed by {predicate_data['distributor'][0]}")
        else:
            parts.append(f" is distributed by {predicate_data['distributor'][0]}")
            has_verb = True

    # Add first aired date
    if "firstAired" in predicate_data:
        if has_verb:
            parts.append(f" and first aired on {predicate_data['firstAired'][0]}")
        else:
            parts.append(f" first aired on {predicate_data['firstAired'][0]}")
            has_verb = True

    # Add last aired date
    if "lastAired" in predicate_data:
        if has_verb:
            parts.append(f", with the last episode airing on {predicate_data['lastAired'][0]}")
        else:
            parts.append(f" with the last episode airing on {predicate_data['lastAired'][0]}")
            has_verb = True

    # Add broadcasted by
    if "broadcastedBy" in predicate_data:
        if has_verb:
            parts.append(f" and broadcasted by {predicate_data['broadcastedBy'][0]}")
        else:
            parts.append(f" broadcasted by {predicate_data['broadcastedBy'][0]}")
            has_verb = True

    # Join all parts into a single complex sentence
    sentence = "".join(parts)
    if not sentence.endswith("."):
        sentence += "."

    return sentence

# EVOLVE-BLOCK-END
